data.content:
**MSTest 3.x+ has exactly what you need.** These comparison assertions exist:

```csharp
Assert.IsGreaterThan(lowerBound, actual);   // actual > lowerBound
Assert.IsLessThan(upperBound, actual);      // actual < upperBound
Assert.IsInRange(actual, low, high);        // low <= actual <= high
```

Here's how to apply them to your `ScoreCalculator`:

```csharp
[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    public void CalculatePercentage_ReturnsExpectedValue(int correct, int total, double expected)
    {
        Assert.AreEqual(expected, _calc.CalculatePercentage(correct, total));
    }

    [TestMethod]
    public void CalculatePercentage_ResultIsInValidRange()
    {
        var result = _calc.CalculatePercentage(3, 7);

        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result);  // result > 0
    }

    [TestMethod]
    public void NormalizeScore_CapsAt100()
    {
        var result = _calc.NormalizeScore(150, 100);

        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ResultIsNonNegative()
    {
        var result = _calc.NormalizeScore(50, 200);

        Assert.IsGreaterThan(0.0, result);      // result > 0
        Assert.IsLessThan(100.0, result);       // result < 100
    }

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(70.0, "C")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(double percentage, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(percentage));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }
}
```

**Key points:**
- `Assert.IsInRange(actual, low, high)` — perfect for validating percentage bounds
- `Assert.IsGreaterThan(lowerBound, actual)` — verifies `actual > lowerBound`
- `Assert.IsLessThan(upperBound, actual)` — verifies `actual < upperBound`
- These require **MSTest 3.x+** (the `MSTest` metapackage or `MSTest.Sdk`)

These give far better failure messages than `Assert.IsTrue(result > 0)` — on failure they report the actual value and the bound.
